#include <stdio.h>
#include <stdint.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int64_t N, M, X; scanf("%lld %lld %lld", &N, &M, &X);
        int64_t ans;
        if (X == M) ans = 0;
        else ans = (N * X) / (X + 1);
        printf("%lld\n", ans);
    }
    return 0;
}

