#!/usr/bin/env python3
import sys
def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it)); M = int(next(it)); X = int(next(it))
        if X == M:
            out.append('0')
        else:
            out.append(str((N * X) // (X + 1)))
    sys.stdout.write('\n'.join(out))
if __name__ == "__main__":
    main()

